import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import { 
  Cpu, LayoutDashboard, TrendingUp, LogOut, 
  Terminal, Menu, X, Globe, Archive 
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { isDarkMode } = useTheme(); 
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  // Standardized Link Style
  const navLinkStyle = (path) => ({
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    fontSize: '11px',
    fontWeight: 700,
    textTransform: 'uppercase',
    letterSpacing: '0.05em',
    padding: '0.5rem 0.8rem',
    borderRadius: '10px',
    transition: 'all 0.25s ease',
    color: isActive(path) ? 'var(--accent-primary)' : 'var(--text-secondary)',
    backgroundColor: isActive(path) ? 'var(--accent-muted)' : 'transparent',
    border: isActive(path) ? '1px solid var(--accent-primary)' : '1px solid transparent',
  });

  return (
    <div style={{ position: 'sticky', top: 0, zIndex: 1000, padding: '1rem' }}>
      <nav style={{
        maxWidth: '1200px',
        margin: '0 auto',
        background: 'var(--surface-glass)',
        backdropFilter: 'blur(18px)',
        WebkitBackdropFilter: 'blur(18px)',
        border: '1px solid var(--surface-border)',
        borderRadius: '18px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0.6rem 1.2rem',
        boxShadow: 'var(--shadow-elevated)'
      }}>
        
        {/* ── Brand / Logo ── */}
        <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none', color: 'var(--text-primary)' }}>
          <div style={{
            width: '34px', height: '34px', borderRadius: '10px',
            background: 'var(--accent-muted)', border: '1px solid var(--accent-primary)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0 0 12px var(--accent-glow)'
          }}>
            <Cpu size={18} color="var(--accent-primary)" />
          </div>
          <span style={{ fontWeight: 800, fontSize: '0.9rem', letterSpacing: '0.12em' }}>FINIFY_AI</span>
        </Link>

        {/* ── Desktop Navigation ── */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }} className="nav-desktop">
          {user ? (
            <>
              <Link to="/dashboard" style={navLinkStyle('/dashboard')}>
                <LayoutDashboard size={14}/> Dashboard
              </Link>
              <Link to="/generate" style={navLinkStyle('/generate')}>
                <TrendingUp size={14}/> Strategy
              </Link>
              <Link to="/live" style={navLinkStyle('/live')}>
                <Globe size={14}/> Live_Pulse
              </Link>
              <Link to="/vault" style={navLinkStyle('/vault')}>
                <Archive size={14}/> Vault
              </Link>
              
              <div style={{ width: '1px', height: '20px', background: 'var(--surface-border)', margin: '0 0.5rem' }} />
              
              <ThemeToggle />
              <button 
                onClick={handleLogout} 
                style={{ 
                  background: 'rgba(239, 68, 68, 0.1)', 
                  border: '1px solid rgba(239, 68, 68, 0.2)', 
                  color: '#ef4444', 
                  cursor: 'pointer', 
                  padding: '0.5rem', 
                  borderRadius: '8px',
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'all 0.2s ease'
                }}
                onMouseEnter={e => e.currentTarget.style.background = 'rgba(239, 68, 68, 0.2)'}
                onMouseLeave={e => e.currentTarget.style.background = 'rgba(239, 68, 68, 0.1)'}
              >
                <LogOut size={16} />
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={navLinkStyle('/login')}>
                <Terminal size={14}/> Access
              </Link>
              <Link to="/register" style={{ 
                ...navLinkStyle('/register'), 
                background: 'var(--accent-primary)', 
                color: '#000',
                boxShadow: '0 0 15px var(--accent-glow)' 
              }}>
                Initialize
              </Link>
              <ThemeToggle />
            </>
          )}
        </div>

        {/* ── Mobile Menu Toggle ── */}
        <button 
          className="nav-mobile-toggle" 
          onClick={() => setMobileOpen(!mobileOpen)} 
          style={{ display: 'none', background: 'none', border: 'none', color: 'var(--text-primary)', cursor: 'pointer' }}
        >
          {mobileOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </nav>

      {/* ── Mobile Dropdown Menu ── */}
      {mobileOpen && (
        <div style={{
          marginTop: '0.5rem',
          background: 'var(--surface-glass)',
          backdropFilter: 'blur(16px)',
          border: '1px solid var(--surface-border)',
          borderRadius: '16px',
          padding: '1rem',
          display: 'flex',
          flexDirection: 'column',
          gap: '0.5rem'
        }}>
          {user ? (
            <>
              <Link to="/dashboard" style={navLinkStyle('/dashboard')} onClick={() => setMobileOpen(false)}>Dashboard</Link>
              <Link to="/generate" style={navLinkStyle('/generate')} onClick={() => setMobileOpen(false)}>Strategy</Link>
              <Link to="/live" style={navLinkStyle('/live')} onClick={() => setMobileOpen(false)}>Live Pulse</Link>
              <Link to="/vault" style={navLinkStyle('/vault')} onClick={() => setMobileOpen(false)}>Vault</Link>
              <button onClick={handleLogout} style={{ textAlign: 'left', padding: '0.5rem', color: '#ef4444', background: 'none', border: 'none', fontWeight: 700 }}>LOGOUT</button>
            </>
          ) : (
            <>
              <Link to="/login" style={navLinkStyle('/login')} onClick={() => setMobileOpen(false)}>Access</Link>
              <Link to="/register" style={navLinkStyle('/register')} onClick={() => setMobileOpen(false)}>Initialize</Link>
            </>
          )}
        </div>
      )}

      <style>{`
        @media (max-width: 980px) {
          .nav-desktop { display: none !important; }
          .nav-mobile-toggle { display: block !important; }
        }
      `}</style>
    </div>
  );
};

export default Navbar;
